import{_ as r,c as a,o as t,ag as o}from"./chunks/framework.ELrfyV9R.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status ":"pending","source":"web-clipper","url":"https://x.com/IceBearMiner/status/2019409133355807197","created":"2026-03-07T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/一个人，调用一支 AI 军队。.md","filePath":"ai/bookmark/一个人，调用一支 AI 军队。.md","lastUpdated":1772872223000}'),l={name:"ai/bookmark/一个人，调用一支 AI 军队。.md"};function p(n,e,s,i,c,g){return t(),a("div",null,e[0]||(e[0]=[o('<p>看完don哥的系统搭建，我也来分享一下自己的系统</p><p>我是如何把 AI 变成&quot;可智能编排的工具&quot;的？</p><h2 id="首先搞懂几个词" tabindex="-1">首先搞懂几个词 <a class="header-anchor" href="#首先搞懂几个词" aria-label="Permalink to &quot;首先搞懂几个词&quot;">​</a></h2><p><strong>Skill 是什么？</strong></p><p>就是一个 教程 文件。你提前写好遇到这类问题该怎么解决，存成 .md 文件，放进 .claude/skills/ 目录。下次 Claude Code 遇到类似问题，就按你写的套路来。</p><p><strong>工作流是什么？</strong></p><p>一个活儿需要好几步：先写代码、再写测试、最后审查。你可以写一个工作流甚至skills组合，告诉 AI：按这个顺序，依次调用这几个 Skill。它就会像流水线一样自动跑完。</p><p><strong>自动识别怎么实现的？</strong></p><p>靠总指挥 Skill。你在里面写路由规则：用户说写代码就调 code-gen，说帮我理解 xxx就调学习流程。AI 读到这个规则，就知道该派谁干活。</p><p><strong>这些东西住在哪？</strong></p><p>你电脑上的 .claude/skills/ 目录。没有就自己建。文章后面的目录结构，就是我这个目录里的样子。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>大多数人用 AI 是这样的：</p><blockquote><p>有需求 → 问 AI → 复制代码 → 下次？重来一遍。</p></blockquote><p>每次都在重新发明轮子。</p><p>我的用法不一样：</p><blockquote><p>有需求 → 总指挥判断复杂度 → 挑合适的 Skill 组合 → 编排器协调执行 → 质量门禁检查 → 结果留档。</p></blockquote><p><strong>前者是散兵游勇，后者是正规军。</strong> 散兵打完就散，正规军打完还复盘、升级装备。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><p>.claude/skills/_architecture/ │ ├── L0 层：决策层（三个总指挥） │ ├── meta-commander/ # 管代码 │ ├── evaluation-commander/ # 管评审 │ └── learning-commander/ # 管学习 │ ├── L1 层：协调层（九个编排器） │ ├── code-orchestrator/ │ ├── doc-orchestrator/ │ ├── data-orchestrator/ │ └── ...等等 │ ├── L2 层：干活层（46 个执行 Skills） │ ├── core/ # 核心款，28 个 │ ├── extended/ # 扩展款，14 个 │ └── experimental/ # 实验款，4 个 │ ├── genesis/ # 创生层 │ └── prime-mover/ # 负责生新 Skill │ └── infra/ # 基础设施 │ ├── │ ├── skill-registry/ # 注册管理 │ ├── eval-engine/ # 评测 │ └── rlaif-engine/ # 自我迭代 │ └──meta-commander/ <a href="https://x.com/search?q=%23%E6%98%A0%E5%B0%84%E8%A1%A8&amp;src=hashtag_click" target="_blank" rel="noreferrer">#映射表</a> └──evaluation-commander/ <a href="https://x.com/search?q=%23%E6%98%A0%E5%B0%84%E8%A1%A8&amp;src=hashtag_click" target="_blank" rel="noreferrer">#映射表</a> └──learning-commander/ <a href="https://x.com/search?q=%23%E6%98%A0%E5%B0%84%E8%A1%A8&amp;src=hashtag_click" target="_blank" rel="noreferrer">#映射表</a> └──...</p><h2 id="工作流程拆解" tabindex="-1">工作流程拆解 <a class="header-anchor" href="#工作流程拆解" aria-label="Permalink to &quot;工作流程拆解&quot;">​</a></h2><p>1. 任务识别</p><p>我说：帮我做个登录功能。</p><p>系统识别出这是代码活儿，交给 <strong>meta-commander</strong>（代码总指挥）。</p><p>总指挥干两件事：判断复杂度、选执行路径。</p><ul><li>S 级（简单）→ 直接叫 code-gen 干</li><li>M 级（中等）→ 叫 code-orchestrator 协调</li><li>L 级（复杂）→ 叫 multi-agent-orchestrator 联合作战</li><li>XL 级（现有能力不够）→ 叫 prime-mover 现场孵化新 Skill</li></ul><p>2. 编排执行</p><p>假设是 M 级，需要写代码、写测试、做审查。</p><p>code-orchestrator 自动安排：</p><p>code-gen 写代码 ↓ test-gen 写测试 ↓ code-review 审代码 ↓ 全过？交货。没过？打回重来。</p><p>一句话全丢给他自己跑</p><p>3. 多轮评审</p><p>如果我问：React 和 Vue，这个项目用哪个好？</p><p>系统切到 <strong>evaluation-commander</strong>（评审总指挥），启动多轮评审：</p><p><strong>Round 1：初筛</strong> 调用subagent三个评审员同时看，投票淘汰最差的。阅读顺序打乱，防止先看的占便宜。</p><p><strong>Round 2：深挖</strong> 剩下的方案，逐个分析 Top 3 缺陷。</p><p><strong>Round 3：对抗</strong> 魔鬼代言人专门攻击第一名。挑出致命伤就翻盘。</p><p><strong>Round 4：收尾</strong> 被淘汰的还有复活机会。最后形成共识。</p><p>这套机制就是为了防止AI 拍脑袋。</p><p>4. 学习流程</p><p>我说一句我想学习消息队列。</p><p>系统切到 <strong>learning-commander</strong>（学习总指挥），四阶段走：</p><p><strong>Phase 1：消化</strong> — 找资料、提炼知识点、用类比解释</p><p><strong>Phase 2：结构化</strong> — 画概念地图、生成图表</p><p><strong>Phase 3：内化</strong> — 自我解释验证、苏格拉底式提问，确保真懂</p><p><strong>Phase 4：应用</strong> — 写练习代码、跑测试，实战巩固</p><p>学习深度可选：</p><ul><li><strong>awareness</strong>（听说过）→ 只跑 Phase 1</li><li><strong>understanding</strong>（理解了）→ Phase 1-2</li><li><strong>application</strong>（会用了）→ Phase 1-3</li><li><strong>mastery</strong>（精通了）→ 全跑→ 记录文档</li></ul><h2 id="skill-的生老病死" tabindex="-1">Skill 的生老病死 <a class="header-anchor" href="#skill-的生老病死" aria-label="Permalink to &quot;Skill 的生老病死&quot;">​</a></h2><p>这套系统最有意思的设计：<strong>Skill 会晋升，也会被淘汰。</strong></p><p>三级体系</p><p><strong>级别数量契约严格度说明</strong>core28严格主力部队extended14标准后备力量experimental4宽松新兵蛋子</p><p>晋升规则</p><p>experimental（适应度 &lt; 0.7） ↓ 适应度 ≥ 0.7 且调用 ≥ 20 次 extended（适应度 0.7-0.9） ↓ 适应度 ≥ 0.9 且调用 ≥ 50 次 core（适应度 &gt; 0.9）</p><p>表现差的？降级。长期没人用的？归档。</p><p>系统自己会越来越能打。</p><h2 id="自我进化" tabindex="-1">自我进化 <a class="header-anchor" href="#自我进化" aria-label="Permalink to &quot;自我进化&quot;">​</a></h2><p>prime-mover：造物主</p><p>现有 Skill 搞不定的活儿，它负责造：</p><ul><li><strong>孵化</strong>：从零造一个</li><li><strong>变异</strong>：基于现有的微调</li><li><strong>融合</strong>：把几个合成一个</li><li><strong>分化</strong>：把一个大的拆成几个专精的</li></ul><p>rlaif-engine：进化引擎</p><p>收集执行反馈 → 分析成功/失败模式 → 自动改进 Skill</p><p>有安全约束：</p><ul><li>单次改动不超过 30%</li><li>连续失败 3 次，冻结迭代</li><li>Core Skill 改动需要人批准</li></ul><h2 id="异常处理" tabindex="-1">异常处理 <a class="header-anchor" href="#异常处理" aria-label="Permalink to &quot;异常处理&quot;">​</a></h2><p>四级升级机制：</p><p><strong>Level 1：自己搞定</strong> 超时就重试，格式歪了就自动修。最多试 3 次。</p><p><strong>Level 2：编排器介入</strong> 输出不合格就换备选 Skill。连续失败就上报更高层。</p><p><strong>Level 3：找人</strong> 改动太大、涉及 Core Skill，得人批准。</p><p><strong>Level 4：急刹车</strong> 适应度暴跌、连续被拒、数据校验失败——冻结一切写操作。</p><h2 id="想自己搭一套" tabindex="-1">想自己搭一套？ <a class="header-anchor" href="#想自己搭一套" aria-label="Permalink to &quot;想自己搭一套？&quot;">​</a></h2><p>几个建议：</p><p><strong>1. 先把架子立起来</strong></p><p>L0：决策层 L1：协调层 L2：执行层</p><p>别上来就追求 46 个 Skill。刚开始3-5 个核心的就够了。</p><p><strong>2. 契约要清晰</strong></p><p>每个 Skill 得说清楚：要什么输入、给什么输出、什么时候该叫它。</p><p><strong>3. 质量门禁别省</strong></p><p>代码写完要审，测试要能跑通，多方案要有评审。</p><p><strong>4. 记录表现</strong></p><p>从第一天就开始记。表现好的升，表现差的降。定期复盘。</p><h2 id="让-claude-code-帮你搭" tabindex="-1">让 Claude Code 帮你搭 <a class="header-anchor" href="#让-claude-code-帮你搭" aria-label="Permalink to &quot;让 Claude Code 帮你搭&quot;">​</a></h2><p>你可以直接把这篇文章丢给 Claude Code，再加上这段：</p><p>我想搭一套技能编排系统。 ​ 我的情况： - 主要场景：[代码开发/内容创作/数据分析/...] - 痛点：[每次从零开始/质量不稳定/...] - 想先解决：[代码生成/代码审查/...] ​ 请帮我： 1. 设计分层结构 2. 定义核心 Skill 契约 3. 建立编排流程 4. 写 CLAUDE.md 项目指南</p><p><strong>几个忠告：</strong></p><ul><li>先做个小 demo，解决一个具体问题</li><li>边用边改，别指望一步到位</li><li>第一天就开始记数据</li><li>每周或每月复盘一次</li><li>别让 所有Skill 的描述同时加载，否则会吃掉 Claude 的上下文窗口，导致它变笨。</li><li>L0 层和 L1 层的指令如果写得太像，AI 会陷入“逻辑回环”。</li></ul><h2 id="热知识" tabindex="-1">热知识： <a class="header-anchor" href="#热知识" aria-label="Permalink to &quot;热知识：&quot;">​</a></h2><p>claude code不仅仅适用于写作和编程，如果你最近大火的龙虾，你可以直接说：帮我安装好<a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">https://github.com/openclaw/openclaw</a>，文档在<a href="https://docs.openclaw.ai/" target="_blank" rel="noreferrer">https://docs.openclaw.ai/</a> 剩下就只需要你提供api和key就OK了</p><p>如果是VPS也可以让CC连接服务器，如果是本地mac mini，查完IP，去Mac 上，选取苹果菜单 &gt;“系统设置”，点按边栏中的“通用” ，然后点按“共享”。或者直接本地登录CC让他一键配置就解决</p>',89)]))}const u=r(l,[["render",p]]);export{h as __pageData,u as default};
